mapper.select:
SELECT * FROM image 
WHERE imageType = '상품' 
  AND articleNO = #{articleNO}

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY p.productNO ASC) AS recNum, p.productNO, p.productCategory, p.productName, p.productDescription, p.productPrice, p.productQty, p.productUpdated, p.productOptions, i.imageFilename FROM product p LEFT JOIN LATERAL ( SELECT imageFilename FROM image WHERE articleNO = p.productNO AND imageType = '상품' ORDER BY imageNO ASC LIMIT 1 ) i ON true
WHERE p.productCategory = #{category}
) sub WHERE recNum BETWEEN ((#{section}-1)+(#{pageNum}-1)*20+1) AND ((#{section}-1)+#{pageNum}*20)

SELECT COUNT(*) FROM (
    SELECT ROW_NUMBER() OVER (PARTITION BY productName ORDER BY productNO ASC) AS rn, productCategory
    FROM product
) sub
WHERE rn = 1


        AND productCategory = #{category}
